esqlQuery.esql:
FROM metrics-generic.otel-default
| WHERE metrics.zookeeper.ruok IS NOT NULL
// Aggregate per node; MIN captures any unhealthy reading in the window
| STATS min_ruok = MIN(metrics.zookeeper.ruok) BY host.name
// ruok = 0 means the node failed its health check and is not serving requests
// This is the most direct signal of ZooKeeper node availability
| WHERE min_ruok == 0
